export const AliasingVsComposition = {
  name: 'Aliasing vs. composition',
  render: () => {
    const aliasEasing = cubicBezierCSS([0, 0, 0.2, 1]);

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${BASE_STYLES}
        .panels { display: grid; grid-template-columns: 1fr 1fr; gap: 32px; margin-top: 8px; }
        .panel { background: #fff; border: 1px solid #e0e0e0; border-radius: 8px; padding: 24px; }
        .panel-title { font-size: 15px; font-weight: 700; color: #1a1a1a; margin-bottom: 4px; }
        .panel-sub { font-size: 12px; color: #777; margin-bottom: 20px; }
        .chain { display: flex; flex-direction: column; gap: 0; margin-bottom: 20px; }
        .chain-box { border: 1px solid #d0d0d0; border-radius: 5px; padding: 10px 14px; background: #fafafa; font-size: 12px; font-family: monospace; color: #333; }
        .chain-box.highlight { background: #f0f7f4; border-color: #00aa55; }
        .chain-arrow { text-align:center; color:#999; font-size:16px; line-height:1.6; }
        .chain-fork { display: flex; gap: 12px; margin-top: 0; }
        .chain-fork-item { flex: 1; border: 1px solid #d0d0d0; border-radius: 5px; padding: 8px 10px; background: #fafafa; font-size: 11px; font-family: monospace; color: #555; }
        .stage { width:100%; height:60px; background:#ececec; border-radius:5px; overflow:hidden; position:relative; margin-bottom:10px; }
        .ref-box { width:50px; height:50px; border-radius:4px; position:absolute; top:5px; left:5px; }
        .chain-label { font-size:11px; color:#888; margin-top:8px; line-height:1.5; }
      </style>
      <div class="page">
        <div class="concept-header">
          <div class="concept-header-title">Aliasing vs. composition</div>
          <div class="concept-header-body">
            Two structurally different operations are at work in semantic motion tokens. Aliasing renames a value — the token is a pointer, and the value type is unchanged at every level of the chain. Composition aggregates different value types into a single token — the result is a new kind of object that neither source token can express alone. Most design system tooling treats these identically. They are not.
          </div>
        </div>

        ${DEPTH_DIAGRAM}

        <div class="panels">
          <!-- Panel A: Aliasing -->
          <div class="panel">
            <div class="panel-title">Panel A — Aliasing</div>
            <div class="panel-sub">A name with intent added. Value structure unchanged.</div>
            <div class="chain">
              <div class="chain-box"><span style="color:#888;">motion.duration.slow</span></div>
              <div class="chain-arrow">↓</div>
              <div class="chain-box"><span style="color:#888;">{duration.400}</span></div>
              <div class="chain-arrow">↓</div>
              <div class="chain-box highlight"><strong>400ms</strong> <span style="color:#888; font-size:10px;">(duration)</span></div>
            </div>
            <div class="stage">
              <div id="boxAlias" style="width:50px; height:50px; background:#0055bb; border-radius:4px; position:absolute; top:5px; left:5px; opacity:0;"></div>
            </div>
            <button class="play-btn" id="playAlias">Play</button>
            <div class="chain-label">The value type — a duration — is the same at every level. Aliasing adds a name with intent but changes nothing structural.</div>
          </div>

          <!-- Panel B: Composition -->
          <div class="panel">
            <div class="panel-title">Panel B — Composition</div>
            <div class="panel-sub">Two different domains combined. The output is a new type.</div>
            <div class="chain">
              <div class="chain-box"><span style="color:#888;">motion.transition.enter</span></div>
              <div class="chain-arrow">↓ forks ↓</div>
              <div class="chain-fork">
                <div class="chain-fork-item"><strong>duration.400</strong><br><span style="color:#aaa;">time domain</span></div>
                <div class="chain-fork-item"><strong>easing.enter</strong><br><span style="color:#aaa;">behavior domain</span></div>
              </div>
              <div class="chain-arrow">↓</div>
              <div class="chain-box highlight"><strong>{400ms + cubic-bezier(0,0,0.2,1)}</strong> <span style="color:#888; font-size:10px;">(transition object)</span></div>
            </div>
            <div class="stage">
              <div id="boxComp" style="width:50px; height:50px; background:#007755; border-radius:4px; position:absolute; top:5px; left:-50px; opacity:0;"></div>
            </div>
            <button class="play-btn" id="playComp">Play</button>
            <div class="chain-label">The chain forks. The output is an object — neither source token can express it alone. One side changing without the other breaks the token's intent.</div>
          </div>
        </div>

        <div class="note">
          Most design system tooling treats aliasing and composition identically — a token is a token. They are not. Aliased tokens propagate a single value. Composite tokens introduce cross-domain dependencies that are invisible until one side changes without updating the other: if <span style="font-family:monospace">duration.400</span> is renamed to <span style="font-family:monospace">duration.slow</span>, every composite referencing it breaks silently.
        </div>
      </div>
    `;

    el.querySelector('#playAlias').addEventListener('click', function() {
      const box = el.querySelector('#boxAlias');
      if (box._animating) return;
      box._animating = true;
      this.disabled = true;
      box.animate(
        [{ opacity: 0, transform: 'translateY(10px)' }, { opacity: 1, transform: 'translateY(0)' }],
        { duration: 400, easing: aliasEasing, fill: 'forwards' }
      ).onfinish = () => { box._animating = false; this.disabled = false; };
    });

    el.querySelector('#playComp').addEventListener('click', function() {
      const box = el.querySelector('#boxComp');
      if (box._animating) return;
      box._animating = true;
      this.disabled = true;
      box.animate(
        [{ opacity: 0, left: '-50px' }, { opacity: 1, left: '5px' }],
        { duration: 400, easing: aliasEasing, fill: 'forwards' }
      ).onfinish = () => { box._animating = false; this.disabled = false; };
    });

    return el;
  },
};

